foreach ($patientPlans as [$pid, $visits]) {
    foreach ($visits as $vIdx => [$did, $daysAgo]) {
        $specId = $doctorSpec[$did];
        $clinArr = $clinicalData[$specId];
        $clin = $clinArr[$vIdx % count($clinArr)];

        // Выбираем слот
        $slotTime = $timeSlots[($pid * 3 + $vIdx * 7) % count($timeSlots)];
        $date = date('Y-m-d', strtotime("-{$daysAgo} days"));
        $slotKey = "{$did}_{$date}_{$slotTime}";

        // Если слот занят — сдвигаем время
        $attempts = 0;
        while (isset($usedSlots[$slotKey]) && $attempts < count($timeSlots)) {
            $slotTime = $timeSlots[($pid * 3 + $vIdx * 7 + $attempts + 1) % count($timeSlots)];
            $slotKey = "{$did}_{$date}_{$slotTime}";
            $attempts++;
        }
        if (isset($usedSlots[$slotKey])) {
            // Сдвигаем на соседний день
            $date = date('Y-m-d', strtotime("-" . ($daysAgo + 1) . " days"));
            $slotKey = "{$did}_{$date}_{$slotTime}";
        }
        $usedSlots[$slotKey] = true;

        $scheduledAt = "{$date} {$slotTime}:00";
        $createdAt = date('Y-m-d H:i:s', strtotime("-" . ($daysAgo + 2) . " days"));

        $insAppt->execute([$pid, 'doctor', $did, $scheduledAt, 'completed', $createdAt]);
        $apptId = (int)$pdo->lastInsertId();

        $startedAt = $scheduledAt;
        $endedAt = date('Y-m-d H:i:s', strtotime($scheduledAt) + 1800 + ($vIdx % 3) * 600);

        $insVisit->execute([$apptId, $startedAt, $endedAt, $clin['complaints'], $clin['examination'], $clin['diagnosis']]);
        $visitId = (int)$pdo->lastInsertId();

        foreach ($clin['drugs'] as $d) {
            $insPresc->execute([$visitId, $d[0], $d[1], $d[2], $d[3]]);
        }

        // Отзыв: ~75% вероятность, с вариацией рейтинга
        $rnd = ($pid * 17 + $vIdx * 13) % 100;
        if ($rnd < 75) {
            $rating = match(true) {
                $rnd < 50 => 5,
                $rnd < 68 => 4,
                default   => 3,
            };
            $texts = $reviewTexts[$rating];
            $text = $texts[($pid + $vIdx) % count($texts)];
            $reviewDate = date('Y-m-d H:i:s', strtotime($scheduledAt) + 3600 * 24 * (2 + $vIdx % 5));
            $isApproved = $rnd < 65 ? 1 : 0; // 65% approved
            $insReview->execute([$pid, $did, $apptId, $rating, $text, $isApproved, $reviewDate]);
        }
    }
}

